import { useEffect, useState } from "react";
import { useParams } from "react-router-dom";
import Navbar from "../components/Navbar";

function ProductDetails() {

  const { id } = useParams();

  const [product, setProduct] =
    useState(null);
    const [darkMode, setDarkMode] =
  useState(false);

const toggleTheme = () => {
  setDarkMode(!darkMode);
};

  useEffect(() => {

    const fetchProduct =
      async () => {

      try {

        const response =
          await fetch(
            `${process.env.REACT_APP_API_URL}/api/products/${id}`
          );

        const data =
          await response.json();

        setProduct(data);

      } catch (error) {

        console.log(error);
      }
    };

    fetchProduct();

  }, [id]);

  if (!product) {
    return <h2>Loading...</h2>;
  }

  return (
    <div
      style={{
        padding: "40px"
      }}
    >

      <h1>
        {product.name}
      </h1>

      <p>
        {product.description}
      </p>

      <h2>
        ₹{product.price}
      </h2>

      <p>
        Category:
        {" "}
        {product.category}
      </p>

      <p>
        Stock:
        {" "}
        {product.stock}
      </p>

    </div>
  );
}

export default ProductDetails;
